package main

import (
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"math/big"
)

const (
	tokenLength = 32
	charset     = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
)

// GenerateSessionToken generates a cryptographically secure random
// alphanumeric session token of 32 characters.
func GenerateSessionToken() (string, error) {
	token := make([]byte, tokenLength)
	charsetLen := big.NewInt(int64(len(charset)))

	for i := 0; i < tokenLength; i++ {
		// Use crypto/rand for cryptographically secure randomness
		randomIndex, err := rand.Int(rand.Reader, charsetLen)
		if err != nil {
			return "", fmt.Errorf("failed to generate secure random number: %w", err)
		}
		token[i] = charset[randomIndex.Int64()]
	}

	return string(token), nil
}

// GenerateSessionTokenHex generates a cryptographically secure random
// session token as a hex-encoded string of 32 characters (16 random bytes).
func GenerateSessionTokenHex() (string, error) {
	bytes := make([]byte, tokenLength/2) // 16 bytes = 32 hex characters
	_, err := rand.Read(bytes)
	if err != nil {
		return "", fmt.Errorf("failed to generate secure random bytes: %w", err)
	}
	return hex.EncodeToString(bytes), nil
}

func main() {
	// Generate an alphanumeric session token
	token, err := GenerateSessionToken()
	if err != nil {
		fmt.Printf("Error generating session token: %v\n", err)
		return
	}
	fmt.Printf("Alphanumeric Session Token: %s (length: %d)\n", token, len(token))

	// Generate a hex-encoded session token
	hexToken, err := GenerateSessionTokenHex()
	if err != nil {
		fmt.Printf("Error generating hex session token: %v\n", err)
		return
	}
	fmt.Printf("Hex Session Token:          %s (length: %d)\n", hexToken, len(hexToken))
}